INSERT INTO public.university_programs (university_id, program_name, degree_type, major, description, ba_program_id) VALUES
(88, 'Informatik 2-Fach-Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen Anmerkung der Hochschule: 2-Fach-Bachelor (polyvalentes Studium für eine fachwissenschaftliche oder auf ein Lehramt an Gymnasien und Gesamtschulen, oder für zwei allgemeinbildende Fächer an Berufskollegs bezogene Ausbildung) Lehramt: Master of Education in Informatik', '78847090'),(352, 'Informatik 2-Fach-Bachelor', 'Bachelor', 'Lehramt an berufsbildenden/beruflichen Schulen/Berufskollegs (grundständig außer Staatsexamen)', 'Schwerpunkte: Anwendungen und Auswirkungen, Fachdidaktik, Grundlagen der Informatik, Programmieren und Programmiersprachen, Rechnersysteme (und Betriebssysteme) Anmerkung der Hochschule: Das Fach ist in Kombination mit einem zweiten Fach in den Studiengängen Fächerübergreifender Bachelor und Bachelor Technical Education studierbar. Je nach Fächerkombination qualifiziert der Abschluss für einen weit...', '78847873'),(354, 'Informatik B.A. Bildung im Sekundarbereich (Bezug Lehramt Sekundarstufe I)', 'Bachelor', 'Lehramt für Schularten der Sekundarstufe I (grundständig außer Staatsexamen)', 'Inhalte bitte bei der Hochschule erfragen', '199248919'),(354, 'Informatik B.A. Sonderpädagogik (Bezug Lehramt Sonderpädagogik)', 'Bachelor', 'Lehramt an Förderschulen/für Sonderpädagogik (grundständig außer Staatsexamen)', 'Inhalte bitte bei der Hochschule erfragen', '199248918'),(79, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Algorithmen und Datenstrukturen, Big Data Engineering, Mathematische Grundlagen, Nebenläufige Programmierung, Programmierung, Softwarepraktikum, Systemarchitektur, Theoretische Informatik Anmerkung der Hochschule: Ab dem 5. Semester werden die Veranstaltungen größtenteils in englischer Sprache angeboten.', '73024053'),(88, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen', '78847316'),(136, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Anwendungsentwicklung, Daten- und Prozessanalyse, Digitale Vernetzung, Systemintegration Anmerkung der Hochschule: Inhaltliche Verzahnung der Ausbildung zur Fachinformatikerin/zum Fachinformatiker mit dem Studium; Lernorte: Hochschule, ausbildendes Unternehmen und Berufsschule. Orientierung an klassischer Fünf-Tage-Woche.', '148803313'),(230, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Allgemeine Informatik, Angewandte Informatik, Betriebliche Informatik, Programm-Ingenieurwesen (Softwareengineering), Technisches Ingenieurwesen der Informatik', '73424275'),(281, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen', '73433674'),(226, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: IT-Sicherheit, IT-Systemintegration, Wirtschaftsinformatik', '73423873'),(158, 'Informatik Bachelor', 'Bachelor', 'Mathematik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen', '253112441'),(202, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Datenbanken und Grundlagen Technischer Informatik, Theoretische Informatik und Algorithmen in C/C++(Programmiersprache) Anmerkung der Hochschule: Dieses Fach kann im fachwissenschaftlichen Kombi-Bachelor als Kernfach, Nebenfach oder als Kleines Nebenfach studiert werden. Weitere Informationen finden Sie auf den Webseiten der Universität Bielefeld.', '220594922'),(64, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Künstliche Intelligenz, Projektbasierte Lehre, Software-Entwicklung, Web-Entwicklung Anmerkung der Hochschule: Studiengangleiter Prof. Dr. Sven Klaus bachelor.ib@informatik.hs-mannheim.de Anzahl der Studienplätze: 86 (56 Wintersemester / 30 Sommersemester)', '73429493'),(34, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Elektrotechnik, Mathematik, Physik, Wirtschaftswissenschaft', '92680876'),(239, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Erziehungswissenschaften, Fachdidaktik Informatik, Logik und Algorithmen, Modellbasierte Softwareentwicklung, Modell und Algorithmen Anmerkung der Hochschule: Kombinationsbachelor', '19329250'),(316, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen Anmerkung der Hochschule: Regelstudienzeit: 6 Semester bzw. 7 Semester mit Praxissemester', '73428329'),(286, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Datenbanken und Rechnernetze, Grundlagen und Methoden der Softwaretechnik, Modellierung und Programmierung, Schlüsselqualifikationen, Theorie der Informatik und Mathematik Anmerkung der Hochschule: Bewerbung nur über unser online Bewerbungsportal unter bewerbung.uni-koblenz.de', '73427740'),(46, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen', '73025660'),(303, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Inhalte bitte bei der Hochschule erfragen', '73026845'),(23, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Informatik, Mathematik, Modellieren und Entwerfen von Software-Systemen Anmerkung der Hochschule: Das Bachelor-Studium der Informatik vermittelt einen fundierten und umfassenden Einblick in die Zukunftstechnologie Informatik. Die fachlichen Schwerpunkte beinhalten neben dem notwendigen mathematischen Rüstzeug die Grundlagen des Programmierens, den Entwurf komplexer Software-Systeme un...', '73026033'),(250, 'Informatik Bachelor', 'Bachelor', 'Informatik (grundständig)', 'Schwerpunkte: Biomedizinische Informatik, Eingebettete Systeme, Informationssicherheit, Komplexe Softwaresysteme, Medieninformatik, Telekommunikation, Wirtschaftsinformatik Anmerkung der Hochschule: Für fachliche Beratung wenden Sie sich an den Dekan: fb02.dekan@h-brs.de Internationaler Doppelabsch